302→            db.endTransaction();
303→        }
304→    }
305→
306→
307→    public static String getTagLastUpdated(ReaderTag tag) {
308→        if (tag == null) {
309→            return "";
310→        }
311→        String[] args = {tag.getTagSlug(), Integer.toString(tag.tagType.toInt())};
312→        return SqlUtils.stringForQuery(ReaderDatabase.getReadableDb(),
313→                                       "SELECT date_updated FROM tbl_tags WHERE tag_slug=? AND tag_type=?",
314→                                       args);
315→    }
316→
317→    public static void setTagLastUpdated(ReaderTag tag) {
318→        updateTagLastUpdated(tag, new Date());
319→    }
320→
321→    public static void clearTagLastUpdated(ReaderTag tag) {
322→        updateTagLastUpdated(tag, new Date(0));
323→    }
324→
325→    private static void updateTagLastUpdated(ReaderTag tag, Date newDate) {
326→        if (tag == null) {
327→            return;
328→        }
329→
330→        String date = DateTimeUtils.iso8601FromDate(newDate);
331→        String sql = "UPDATE tbl_tags SET date_updated=?1 WHERE tag_slug=?2 AND tag_type=?3";
332→        SQLiteStatement stmt = ReaderDatabase.getWritableDb().compileStatement(sql);
333→        try {
334→            stmt.bindString(1, date);
335→            stmt.bindString(2, tag.getTagSlug());
336→            stmt.bindLong(3, tag.tagType.toInt());
337→            stmt.execute();
338→        } finally {
339→            SqlUtils.closeStatement(stmt);
340→        }
341→    }
342→
343→    /*
344→     * determine whether the passed tag should be auto-updated based on when it was last updated
345→     */
346→    public static boolean shouldAutoUpdateTag(ReaderTag tag) {
347→        int minutes = minutesSinceLastUpdate(tag);
348→        if (minutes == NEVER_UPDATED) {
349→            return true;
350→        }
351→        return (minutes >= ReaderConstants.READER_AUTO_UPDATE_DELAY_MINUTES);
352→    }
353→
354→    private static final int NEVER_UPDATED = -1;
355→
356→    private static int minutesSinceLastUpdate(ReaderTag tag) {
357→        if (tag == null) {
358→            return 0;
359→        }
360→
361→        String updated = getTagLastUpdated(tag);
362→        if (TextUtils.isEmpty(updated)) {
363→            return NEVER_UPDATED;
364→        }
365→
366→        Date dtUpdated = DateTimeUtils.dateFromIso8601(updated);
367→        if (dtUpdated == null) {
368→            return 0;
369→        }
370→
371→        Date dtNow = new Date();
372→        return DateTimeUtils.minutesBetween(dtUpdated, dtNow);
373→    }
374→}
