  1→package org.wordpress.android.ui.reader.actions;
  2→
  3→import androidx.annotation.NonNull;
  4→
  5→import com.wordpress.rest.RestRequest;
  6→
  7→import org.greenrobot.eventbus.EventBus;
  8→import org.json.JSONArray;
  9→import org.json.JSONObject;
 10→import org.wordpress.android.WordPress;
 11→import org.wordpress.android.datasets.ReaderTagTable;
 12→import org.wordpress.android.models.ReaderTag;
 13→import org.wordpress.android.models.ReaderTagList;
 14→import org.wordpress.android.models.ReaderTagType;
 15→import org.wordpress.android.ui.reader.ReaderConstants;
 16→import org.wordpress.android.ui.reader.ReaderEvents;
 17→import org.wordpress.android.ui.reader.actions.ReaderActions.ActionListener;
 18→import org.wordpress.android.ui.reader.utils.ReaderUtils;
 19→import org.wordpress.android.util.AppLog;
 20→import org.wordpress.android.util.AppLog.T;
 21→import org.wordpress.android.util.JSONUtils;
 22→import org.wordpress.android.util.VolleyUtils;
 23→
 24→import java.util.HashMap;
 25→import java.util.List;
 26→import java.util.Map;
 27→
 28→public class ReaderTagActions {
 29→    private ReaderTagActions() {
 30→        throw new AssertionError();
 31→    }
 32→
 33→    public static boolean deleteTag(final ReaderTag tag,
 34→                                    final ReaderActions.ActionListener actionListener,
 35→                                    final boolean isLoggedIn) {
 36→        if (tag == null) {
 37→            ReaderActions.callActionListener(actionListener, false);
 38→            return false;
 39→        }
 40→
 41→        boolean result;
 42→        if (!isLoggedIn) {
 43→            result = deleteTagsLocallyOnly(actionListener, tag);
 44→        } else {
 45→            result = deleteTagsLocallyAndRemotely(actionListener, tag);
 46→        }
 47→
 48→        return result;
 49→    }
 50→
 51→    private static boolean deleteTagsLocallyOnly(ActionListener actionListener, ReaderTag tag) {
 52→        ReaderTagTable.deleteTag(tag);
 53→        ReaderActions.callActionListener(actionListener, true);
 54→        EventBus.getDefault().post(new ReaderEvents.FollowedTagsChanged(true));
 55→
 56→        return true;
 57→    }
 58→
 59→    private static boolean deleteTagsLocallyAndRemotely(ActionListener actionListener, ReaderTag tag) {
 60→        final String tagNameForApi = ReaderUtils.sanitizeWithDashes(tag.getTagSlug());
 61→        final String path = "read/tags/" + tagNameForApi + "/mine/delete";
 62→
 63→        com.wordpress.rest.RestRequest.Listener listener = jsonObject -> {
 64→            AppLog.i(T.READER, "delete tag succeeded");
 65→            ReaderActions.callActionListener(actionListener, true);
 66→        };
 67→
 68→        RestRequest.ErrorListener errorListener = volleyError -> {
 69→            // treat it as a success if the error says the user isn't following the deleted tag
 70→            String error = VolleyUtils.errStringFromVolleyError(volleyError);
 71→            if (error.equals("not_subscribed")) {
 72→                AppLog.w(T.READER, "delete tag succeeded with error " + error);
 73→                ReaderActions.callActionListener(actionListener, true);
 74→                return;
 75→            }
 76→
 77→            AppLog.w(T.READER, " delete tag failed");
 78→            AppLog.e(T.READER, volleyError);
 79→
 80→            // add back original tag
 81→            ReaderTagTable.addOrUpdateTag(tag);
 82→
 83→            ReaderActions.callActionListener(actionListener, false);
 84→        };
 85→        ReaderTagTable.deleteTag(tag);
 86→        WordPress.getRestClientUtilsV1_1().post(path, listener, errorListener);
 87→
 88→        return true;
 89→    }
 90→
 91→    public static boolean addTag(@NonNull final ReaderTag tag,
 92→                                 final ReaderActions.ActionListener actionListener,
 93→                                 final boolean isLoggedIn) {
 94→        ReaderTagList tags = new ReaderTagList();
 95→        tags.add(tag);
 96→        return addTags(tags, actionListener, isLoggedIn);
 97→    }
 98→
 99→    public static boolean addTags(@NonNull final List<ReaderTag> tags,
100→                                  final boolean isLoggedIn) {
101→        return addTags(tags, null, isLoggedIn);
102→    }
103→
104→    public static boolean addTags(@NonNull final List<ReaderTag> tags,
105→                                  final ReaderActions.ActionListener actionListener,
106→                                  final boolean isLoggedIn) {
107→        ReaderTagList newTags = new ReaderTagList();
108→        for (ReaderTag tag : tags) {
109→            final String tagNameForApi = ReaderUtils.sanitizeWithDashes(tag.getTagSlug());
110→            String endpoint = "/read/tags/" + tagNameForApi + "/posts";
111→
112→            ReaderTag newTag = new ReaderTag(
113→                    tag.getTagSlug(),
114→                    tag.getTagDisplayName(),
115→                    tag.getTagTitle(),
116→                    endpoint,
117→                    ReaderTagType.FOLLOWED);
118→            newTags.add(newTag);
119→        }
120→        boolean result;
121→        if (!isLoggedIn) {
122→            result = saveTagsLocallyOnly(actionListener, newTags);
123→        } else {
124→            result = saveTagsLocallyAndRemotely(actionListener, newTags);
125→        }
126→
127→        return result;
128→    }
129→
130→    private static boolean saveTagsLocallyOnly(ActionListener actionListener, ReaderTagList newTags) {
131→        ReaderTagTable.addOrUpdateTags(newTags);
132→        ReaderActions.callActionListener(actionListener, true);
133→        EventBus.getDefault().post(new ReaderEvents.FollowedTagsChanged(true));
134→
135→        return true;
136→    }
137→
138→    private static boolean saveTagsLocallyAndRemotely(ActionListener actionListener,
139→                                                   ReaderTagList newTags) {
140→        ReaderTagList existingFollowedTags = ReaderTagTable.getFollowedTags();
141→
142→        RestRequest.Listener listener = jsonObject -> {
143→            AppLog.i(T.READER, "add tag succeeded");
144→            // the response will contain the list of the user's followed tags
145→            ReaderTagList followedTags = parseFollowedTags(jsonObject);
146→            ReaderTagTable.replaceFollowedTags(followedTags);
147→            if (actionListener != null) {
148→                ReaderActions.callActionListener(actionListener, true);
149→            }
150→            EventBus.getDefault().post(new ReaderEvents.FollowedTagsChanged(true));
151→        };
152→
153→        RestRequest.ErrorListener errorListener = volleyError -> {
154→            // treat is as a success if we're adding a tag and the error says the user is
155→            // already following it
156→            String error = VolleyUtils.errStringFromVolleyError(volleyError);
157→            if (error.equals("already_subscribed")) {
158→                AppLog.w(T.READER, "add tag succeeded with error " + error);
159→                if (actionListener != null) {
160→                    ReaderActions.callActionListener(actionListener, true);
161→                }
162→                EventBus.getDefault().post(new ReaderEvents.FollowedTagsChanged(true));
163→                return;
164→            }
165→
166→            AppLog.w(T.READER, "add tag failed");
167→            AppLog.e(T.READER, volleyError);
168→
169→            // revert on failure
170→            ReaderTagTable.replaceFollowedTags(existingFollowedTags);
171→            if (actionListener != null) {
172→                ReaderActions.callActionListener(actionListener, false);
173→            }
174→            EventBus.getDefault().post(new ReaderEvents.FollowedTagsChanged(false));
175→        };
176→
177→        ReaderTagTable.addOrUpdateTags(newTags);
178→
179→        final String path = "read/tags/mine/new";
180→
181→        Map<String, String> params = new HashMap<>();
182→        String newTagSlugs = ReaderUtils.getCommaSeparatedTagSlugs(newTags);
183→        params.put("tags", newTagSlugs);
184→
185→        WordPress.getRestClientUtilsV1_2().post(path, params, null, listener, errorListener);
186→
187→        return true;
188→    }
189→
190→    /*
191→     * return the user's followed tags from the response to read/tags/{tag}/mine/new
192→     */
193→    /*
194→        {
195→        "added_tag": "84776",
196→        "subscribed": true,
197→        "tags": [
198→            {
199→                "display_name": "fitness",
200→                "ID": "5189",
201→                "slug": "fitness",
202→                "title": "Fitness",
203→                "URL": "https://public-api.wordpress.com/rest/v1.1/read/tags/fitness/posts"
204→            },
205→            ...
206→        }
207→     */
208→    private static ReaderTagList parseFollowedTags(JSONObject jsonObject) {
209→        if (jsonObject == null) {
210→            return null;
211→        }
212→
213→        JSONArray jsonTags = jsonObject.optJSONArray(ReaderConstants.JSON_TAG_TAGS_ARRAY);
214→        if (jsonTags == null || jsonTags.length() == 0) {
215→            return null;
216→        }
217→
218→        ReaderTagList tags = new ReaderTagList();
219→        for (int i = 0; i < jsonTags.length(); i++) {
220→            JSONObject jsonThisTag = jsonTags.optJSONObject(i);
221→            String tagTitle = JSONUtils.getStringDecoded(jsonThisTag, ReaderConstants.JSON_TAG_TITLE);
222→            String tagDisplayName = JSONUtils.getStringDecoded(jsonThisTag, ReaderConstants.JSON_TAG_DISPLAY_NAME);
223→            String tagSlug = JSONUtils.getStringDecoded(jsonThisTag, ReaderConstants.JSON_TAG_SLUG);
224→            String endpoint = JSONUtils.getString(jsonThisTag, ReaderConstants.JSON_TAG_URL);
225→            tags.add(new ReaderTag(tagSlug, tagDisplayName, tagTitle, endpoint, ReaderTagType.FOLLOWED));
226→        }
227→
228→        return tags;
229→    }
230→}
